import React, { useState } from 'react'
import { Canvas, useLoader } from '@react-three/fiber' // <--- Move useLoader here
import { Float, OrbitControls, Text } from '@react-three/drei' // <--- Remove it from here
import { TextureLoader } from 'three'
import confetti from 'canvas-confetti'

const EnvelopeCube = () => {
  const [isOpen, setIsOpen] = useState(false)

  const textures = useLoader(TextureLoader, [
    '/assets/eid1.jpeg',
    '/assets/eid2.jpg',
    '/assets/eid3.jpg',
    '/assets/eid4.jpg',
    '/assets/eid5.jpg',
    '/assets/eid6.jpg'
  ])

  const handleClick = () => {
    setIsOpen(!isOpen)
    if (!isOpen) {
      confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } })
    }
  }

  // Adjusted scale for "little cube" size
  return (
    <group onClick={handleClick} scale={0.6}> 
      {/* Visualizing the "Envelope" Opening: Split the smaller cube */}
      <mesh position={[isOpen ? -1.5 : 0, 0, 0]}>
        <boxGeometry args={[1, 1, 1]} />
        {textures.slice(0, 3).map((tex, i) => (
            <meshStandardMaterial key={i} attach={`material-${i}`} map={tex} />
        ))}
      </mesh>
      <mesh position={[isOpen ? 1.5 : 0, 0, 0]}>
        <boxGeometry args={[1.5, 1.5, 1.5]} />
        {textures.slice(3, 6).map((tex, i) => (
            <meshStandardMaterial key={i} attach={`material-${i}`} map={tex} />
        ))}
      </mesh>

      {/* Floating Eid Mubarak Message */}
      {isOpen && (
        <Float speed={2} floatIntensity={2}>
          <Text position={[0, 2, 0]} color="gold" fontSize={0.8}>
            Eid Mubarak!
          </Text>
        </Float>
      )}
    </group>
  )
}

export default function App() {
  return (
    <Canvas style={{ height: '100vh', background: '#0a192f' }}>
      <ambientLight intensity={0.8} />
      <EnvelopeCube />
      <OrbitControls />
    </Canvas>
  )
}
